INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('promotion-4c199b1b-moex-00002', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-114-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'essay', '甲有子女乙丙丁3 人，甲喪偶後即長年與乙及乙的子女戊己同住，感情
深厚。某日甲因故與丙發生口角，丙出手毆打甲2 拳，甲憤而找律師庚
預立遺囑，將乙丁戊己列為繼承人，並排除丙之繼承權。甲過世後，因
該遺囑僅由甲、庚及 2位見證人蓋章卻未簽名而無效。戊己認為其權益
受侵害，而向庚請求損害賠償。試說明戊己之主張是否有理由。設若甲
之遺囑有效，試說明何者得繼承及其得繼承之比例。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "90a3a0e73e71", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "401", "s": "0502", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00003', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-114-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '下列何種情況當事人不屬於有權收取天然孳息之人？', '["土地所有權人對未採收而自然掉落之果實", "農場主人對其所有之母獸所生之小獸", "果園主人對修剪園中芒果樹落下的枝條", "果園承租人對租賃期滿仍未收取之果實"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "90a3a0e73e71", "answer_pdf_sha1": "af2e32916fff", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "401", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00004', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-114-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '有關法律行為附條件，下列敘述何者正確？', '["基於私法自治，法律行為原則上允許附條件", "離婚可以附條件", "票據行為可以附條件", "若當事人無該條件即不為法律行為，僅條件無效，法律行為仍有效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "90a3a0e73e71", "answer_pdf_sha1": "af2e32916fff", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "401", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00005', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-114-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', 'W在S的土地上種植地瓜葉。下列敘述何者錯誤？', '["地瓜葉還種在土地上時，所有權是S的", "W如果向S合法的承租該土地，則W有收成地瓜葉的權利", "地瓜葉還種在土地上時，沒辦法單獨作為一個物", "如果是W未經S的授權下，擅自種植地瓜，地瓜葉採摘後，所有權是S和W共有的"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "90a3a0e73e71", "answer_pdf_sha1": "af2e32916fff", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "401", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00006', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-114-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '有關無權代理人責任，下列敘述何者正確？', '["本人拒絕承認者，契約行為不生效力，但物權行為有效", "相對人因過失而不知無代理權，無權代理人仍應負責", "無論相對人善惡意，皆得請求無權代理人向其負損害賠償責任", "無權代理人倘能證明自己無過失，即可免責"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "90a3a0e73e71", "answer_pdf_sha1": "af2e32916fff", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "401", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00007', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-114-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '甲有意將A地贈與給乙，為免子孫有意見，雙方合意假裝為買賣。雙方經簽訂買賣契約，甲並以 移轉所有權意思，辦理移轉登記將A地交付給乙。下列敘述何者正確？', '["甲乙間之買賣契約有效", "甲乙間通謀虛偽意思表示，甲或乙皆有撤銷權", "甲乙間之法律行為應適用買賣之規定", "甲乙間之法律行為應適用贈與之規定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "90a3a0e73e71", "answer_pdf_sha1": "af2e32916fff", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "401", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00008', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-114-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '甲遺失名貴戒指，遂刊登廣告聲明對尋獲者贈與其所收藏之 A 古董花瓶。一個月後乙通知甲尋 獲，然該花瓶已在乙尋獲戒指前因甲打掃不慎打破。下列敘述何者正確？', '["依通說，認為乙通知甲為要約，甲贈與花瓶為承諾", "該懸賞廣告契約屬自始客觀不能，應為無效", "由於花瓶已在乙尋獲戒指前滅失，乙不得請求甲負損害賠償責任", "倘乙不知有廣告，則該懸賞廣告契約不生效力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "90a3a0e73e71", "answer_pdf_sha1": "af2e32916fff", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "401", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00009', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-114-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '甲受僱於乙派遣公司，乙公司派遣甲赴丙要派公司擔任公務車司機，依丙公司調度出車服勞務。 甲於出勤時超速撞傷行人A。下列敘述何者正確？', '["甲與丙公司間是否成立僱傭關係，依其是否有僱傭契約為斷", "乙公司無庸分擔甲行為所引起的風險", "丙公司亦為甲之僱用人", "倘A對甲久不求償致請求權消滅時效已完成，乙公司不可援用甲之時效抗辯對抗A"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "90a3a0e73e71", "answer_pdf_sha1": "af2e32916fff", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "401", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00010', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-114-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '甲將電動車1台出售予乙，價金120萬元，乙先交付定金20萬元。若該電動車已於契約成立前 焚燬。下列敘述何者正確？', '["甲若訂約時，即知其不能或可得而知者，對於非因過失而信契約為有效而受損害之乙，應負賠 償責任", "該買賣標的物屬嗣後客觀不能，所締結之買賣契約應為無效", "乙交付定金，其性質具獨立性，與本契約效力如何無涉，甲應加倍返還定金", "電動車焚燬之原因，縱不可歸責於甲，甲仍須負債務不履行之賠償責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "90a3a0e73e71", "answer_pdf_sha1": "af2e32916fff", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "401", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00011', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-114-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '甲將其對乙之債權先後讓與A及B，甲對乙為債權讓與A之通知。下列敘述何者正確？', '["乙因而向A清償，尚不生清償之效力", "B所受之讓與契約，屬於受讓不存在之債權，無效", "B為善意不知情，得主張有善意取得之適用", "甲將債權讓與B，屬於處分現仍存在屬A所有之債權，性質上屬無權處分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "90a3a0e73e71", "answer_pdf_sha1": "af2e32916fff", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "401", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL)
